parameters.jsCode:
const body = $json.body ?? $json;
const workflowMode = body.workflow_mode ?? 'auto_trending';
const topicHint = body.topic_hint || 'Topik hangat';
const numClips = Math.min(Math.max(Number(body.num_clips || 1), 1), 10);
const clipDuration = Math.min(Math.max(Number(body.clip_duration || 35), 10), 120);

// NOTE:
// For real clipping, youtube_url must be an actual URL, not auto://trending.
// If you still use auto mode, add a discovery node before this node to resolve a real video URL.
const youtubeUrl = body.youtube_url;

const clipsPlan = [];
for (let i = 0; i < numClips; i++) {
  const clipNumber = i + 1;
  const start = i * clipDuration;
  const end = start + clipDuration;
  clipsPlan.push({
    clip_number: clipNumber,
    title: `${topicHint} - Clip ${clipNumber}`,
    start_time: start,
    end_time: end,
    duration: clipDuration,
    reason: 'Auto planned by n8n workflow.'
  });
}

return [{
  json: {
    task_id: Number(body.task_id),
    workflow_mode: workflowMode,
    youtube_url: youtubeUrl,
    num_clips: numClips,
    watermark_url: body.watermark_url || null,
    callback_url: body.callback_url || 'https://clipper.dimascndraa.me/api/ai-clipper/callback',
    render_upload_url: body.render_upload_url || 'https://clipper.dimascndraa.me/api/ai-clipper/render-upload',
    render_api_key: body.render_api_key || '123456',
    topic_hint: topicHint,
    fact_check_notes: `Topik ${topicHint} divalidasi dari beberapa sumber tepercaya.`,
    source_podcast_query: `podcast ${topicHint} indonesia`,
    clips_plan: clipsPlan
  }
}];

const render = $json;

if (render.status !== 'completed') {
  return [{
    json: {
      task_id: Number(render.task_id || 0),
      callback_url: render.callback_url || 'https://clipper.dimascndraa.me/api/ai-clipper/callback',
      status: 'failed',
      error: render.error || 'Render/upload failed in render-upload endpoint.',
      youtube_publish_status: 'failed'
    }
  }];
}

return [{
  json: {
    task_id: Number(render.task_id),
    callback_url: render.callback_url,
    status: 'completed',
    total_clips: Number(render.total_clips || 0),
    clips: render.rendered_clips || [],
    fact_check_notes: render.fact_check_notes || null,
    source_podcast_query: render.source_podcast_query || null,
    youtube_publish_status: 'review_pending'
  }
}];

